def find_prime_numbers(n):
    primes = []

    for i in range(2, n + 1):
        is_prime = True
        for j in range(2, i):
            if i % j == 0:
                is_prime = False
                break
        if is_prime:
            primes.append(i)

    return primes

class Solution:
    def checkValidString(self, s: str) -> bool:
        open_stack = []
        star_stack = []
        for i, char in enumerate(s):

            # Add open brackets to open_stack and star to star_stack
            if char == "(":
                open_stack.append(i)
            elif char == "*":
                star_stack.append(i)

            # Check the current opening brackets or star, pop them in case they match the closing bracket
            # If no matching bracket is found, then the expression is not valid.
            elif char == ")":
                if open_stack:
                    open_stack.pop()
                elif star_stack:
                    star_stack.pop()
                else:
                    return False

        # Check the length of the remaining stacks
        while open_stack and star_stack:
            o = open_stack.pop()
            s = star_stack.pop()

            if o > s:
                return False

        return len(open_stack) == 0

def find_most_frequent(s):
    # check for valid input
    assert isinstance(s, str), 'Input must be a string.'
    # create a dictionary for character counts
    count_dict = {} 

    # find all characters
    for i in range(len(s)): 
        if s[i] in count_dict: 
            count_dict[s[i]] += 1
        else: 
            count_dict[s[i]] = 1

    # find most frequent character
    max_count = 0
    frequent_char = ''
    for char in count_dict:
        if count_dict[char] > max_count:
            max_count = count_dict[char]
            frequent_char = char

    # return most frequent character
    return frequent_char

def transpose(A):
    m = len(A)
    n = len(A[0])
    AT = [[0] * m for _ in range(n)]

    for i in range(m):
        for j in range(n):
            AT[j][i] = A[i][j]
    return AT

